diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..9a655f7b5fc3 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1133,6 +1133,16 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,

   if (LHSIsSelect && RHSIsSelect && A == D) {
     // (A ? B : C) op (A ? E : F) -> A ? (B op E) : (C op F)
+    // If the operation is commutative and the arms are swapped, the result
+    // is always the same regardless of the condition: (A ? B : C) op (A ? C : B) -> B op C
+    if (Instruction::isCommutative(Opcode) && B == F && C == E) {
+      if (Value *V = simplifyBinOp(Opcode, B, C, FMF, Q))
+        return V;
+      Value *NewBO = Builder.CreateBinOp(Opcode, B, C, I.getName());
+      if (auto *NewBinOp = dyn_cast<BinaryOperator>(NewBO))
+        NewBinOp->copyIRFlags(&I);
+      return NewBO;
+    }
     Cond = A;
     True = simplifyBinOp(Opcode, B, E, FMF, Q);
     False = simplifyBinOp(Opcode, C, F, FMF, Q);

